export const getCountryByCode = (iso) => COUNTRIES.find(c => c.iso === iso) ?? null;

export const getStatesOfCountry = (countryIso) =>
  (STATES[countryIso] || []).map(s => ({ value: s.iso, label: s.name }));

export const getStateName = (stateCode, countryIso) => {
  const list = STATES[countryIso] || [];
  return list.find(s => s.iso === stateCode)?.name ?? stateCode ?? null;
};

export const getCitiesOfState = (countryIso, stateCode) =>
  (CITIES[countryIso]?.[stateCode] || []).map(name => ({ value: name, label: name }));

export const ALL_COUNTRIES_OPTIONS = COUNTRIES.map(c => ({ value: c.iso, isoCode: c.iso, label: c.name }));
